#!/usr/bin/perl

use strict;
use warnings;
use CGI;

my $cgi = CGI->new;
my $log_dir = "/path/to/log/files";

print $cgi->header('text/plain');

my $filename = $cgi->param('logfile');
if ($filename && $filename =~ /^[a-zA-Z0-9_.-]+$/) {
    my $file_path = "$log_dir/$filename";
    
    if (open(my $fh, '<', $file_path)) {
        while (my $line = <$fh>) {
            print $line;
        }
        close($fh);
    } else {
        print "Error opening file: $!";
    }
} else {
    print "Invalid or missing logfile parameter.";
}